#!/usr/bin/env python3
"""Data quality checker for COCO-format JSON datasets."""

# /// script
# requires-python = ">=3.10"
# dependencies = []
# ///

import json
import sys
from collections import Counter, defaultdict
from pathlib import Path

def check_dataset(path: str) -> list[dict]:
    issues = []

    def issue(severity: str, category: str, msg: str, detail=None):
        issues.append({"severity": severity, "category": category, "message": msg, "detail": detail})

    print(f"\n{'='*60}")
    print(f"Checking: {path}")
    print(f"{'='*60}")

    with open(path) as f:
        data = json.load(f)

    # ── Top-level keys ─────────────────────────────────────────
    EXPECTED_KEYS = {"info", "licenses", "images", "annotations", "categories"}
    present = set(data.keys())
    missing_keys = EXPECTED_KEYS - present
    extra_keys   = present - EXPECTED_KEYS
    if missing_keys:
        issue("ERROR", "schema", f"Missing top-level keys: {missing_keys}")
    if extra_keys:
        issue("WARN", "schema", f"Unexpected top-level keys: {extra_keys}")

    images      = data.get("images", [])
    annotations = data.get("annotations", [])
    categories  = data.get("categories", [])
    licenses    = data.get("licenses", [])

    print(f"  images: {len(images):,}  annotations: {len(annotations):,}  "
          f"categories: {len(categories)}  licenses: {len(licenses)}")

    # ── Images ─────────────────────────────────────────────────
    img_ids = [img.get("id") for img in images]
    img_id_set = set()
    dup_img_ids = []
    for iid in img_ids:
        if iid in img_id_set:
            dup_img_ids.append(iid)
        img_id_set.add(iid)
    if dup_img_ids:
        issue("ERROR", "images", f"Duplicate image IDs ({len(dup_img_ids)} dupes)",
              dup_img_ids[:10])

    null_img_ids = [i for i, img in enumerate(images) if img.get("id") is None]
    if null_img_ids:
        issue("ERROR", "images", f"{len(null_img_ids)} images have null/missing id")

    REQUIRED_IMG_FIELDS = {"id", "file_name", "width", "height"}
    img_missing_fields = defaultdict(int)
    img_zero_dim = 0
    img_negative_dim = 0
    img_missing_license = 0
    license_ids = {lic["id"] for lic in licenses}
    img_bad_license = 0
    img_empty_filename = 0

    for img in images:
        for f in REQUIRED_IMG_FIELDS:
            if f not in img:
                img_missing_fields[f] += 1
        w, h = img.get("width", -1), img.get("height", -1)
        if w == 0 or h == 0:
            img_zero_dim += 1
        if w < 0 or h < 0:
            img_negative_dim += 1
        if "license" not in img:
            img_missing_license += 1
        elif img["license"] not in license_ids and license_ids:
            img_bad_license += 1
        fn = img.get("file_name", "")
        if not fn or not str(fn).strip():
            img_empty_filename += 1

    for field, cnt in img_missing_fields.items():
        issue("ERROR", "images", f"{cnt} images missing required field '{field}'")
    if img_zero_dim:
        issue("ERROR", "images", f"{img_zero_dim} images have zero width or height")
    if img_negative_dim:
        issue("ERROR", "images", f"{img_negative_dim} images have negative dimension")
    if img_missing_license:
        issue("WARN", "images", f"{img_missing_license} images missing 'license' field")
    if img_bad_license:
        issue("WARN", "images", f"{img_bad_license} images reference undefined license IDs")
    if img_empty_filename:
        issue("ERROR", "images", f"{img_empty_filename} images have empty/missing file_name")

    # Check for duplicate file names
    file_names = [img.get("file_name") for img in images if img.get("file_name")]
    dup_fnames = [fn for fn, cnt in Counter(file_names).items() if cnt > 1]
    if dup_fnames:
        issue("WARN", "images", f"{len(dup_fnames)} duplicate file_name values",
              dup_fnames[:5])

    # ── Categories ─────────────────────────────────────────────
    cat_ids = [cat.get("id") for cat in categories]
    cat_id_set = set()
    dup_cat_ids = []
    for cid in cat_ids:
        if cid in cat_id_set:
            dup_cat_ids.append(cid)
        cat_id_set.add(cid)
    if dup_cat_ids:
        issue("ERROR", "categories", f"Duplicate category IDs: {dup_cat_ids}")

    cat_names = [cat.get("name") for cat in categories]
    dup_cat_names = [n for n, cnt in Counter(cat_names).items() if cnt > 1]
    if dup_cat_names:
        issue("WARN", "categories", f"Duplicate category names: {dup_cat_names}")

    REQUIRED_CAT_FIELDS = {"id", "name", "supercategory"}
    cat_missing_fields = defaultdict(int)
    for cat in categories:
        for f in REQUIRED_CAT_FIELDS:
            if f not in cat:
                cat_missing_fields[f] += 1
    for field, cnt in cat_missing_fields.items():
        issue("WARN", "categories", f"{cnt} categories missing field '{field}'")

    # ── Annotations ────────────────────────────────────────────
    ann_ids = [ann.get("id") for ann in annotations]
    ann_id_set = set()
    dup_ann_ids = []
    for aid in ann_ids:
        if aid in ann_id_set:
            dup_ann_ids.append(aid)
        ann_id_set.add(aid)
    if dup_ann_ids:
        issue("ERROR", "annotations", f"Duplicate annotation IDs ({len(dup_ann_ids)} dupes)",
              dup_ann_ids[:10])

    REQUIRED_ANN_FIELDS = {"id", "image_id", "category_id"}
    ann_missing_fields = defaultdict(int)
    ann_bad_img_id     = 0
    ann_bad_cat_id     = 0
    ann_neg_area       = 0
    ann_zero_area      = 0
    ann_bad_bbox       = 0   # bbox with w<=0 or h<=0
    ann_no_bbox        = 0
    ann_no_seg         = 0
    ann_neg_iscrowd    = 0
    iscrowd_values     = Counter()

    for ann in annotations:
        for f in REQUIRED_ANN_FIELDS:
            if f not in ann:
                ann_missing_fields[f] += 1
        if ann.get("image_id") not in img_id_set:
            ann_bad_img_id += 1
        if ann.get("category_id") not in cat_id_set:
            ann_bad_cat_id += 1
        area = ann.get("area", None)
        if area is not None:
            if area < 0:
                ann_neg_area += 1
            elif area == 0:
                ann_zero_area += 1
        bbox = ann.get("bbox")
        if bbox is None:
            ann_no_bbox += 1
        else:
            if len(bbox) != 4 or bbox[2] <= 0 or bbox[3] <= 0:
                ann_bad_bbox += 1
        seg = ann.get("segmentation")
        if seg is None or (isinstance(seg, list) and len(seg) == 0):
            ann_no_seg += 1
        ic = ann.get("iscrowd")
        if ic is not None:
            if ic not in (0, 1):
                ann_neg_iscrowd += 1
            iscrowd_values[ic] += 1

    for field, cnt in ann_missing_fields.items():
        issue("ERROR", "annotations", f"{cnt} annotations missing required field '{field}'")
    if ann_bad_img_id:
        issue("ERROR", "annotations",
              f"{ann_bad_img_id} annotations reference image_id not in images list")
    if ann_bad_cat_id:
        issue("ERROR", "annotations",
              f"{ann_bad_cat_id} annotations reference category_id not in categories list")
    if ann_neg_area:
        issue("ERROR", "annotations", f"{ann_neg_area} annotations have negative area")
    if ann_zero_area:
        issue("WARN",  "annotations", f"{ann_zero_area} annotations have zero area")
    if ann_bad_bbox:
        issue("ERROR", "annotations",
              f"{ann_bad_bbox} annotations have invalid bbox (wrong length or non-positive w/h)")
    if ann_no_bbox:
        issue("WARN", "annotations", f"{ann_no_bbox} annotations missing 'bbox'")
    if ann_no_seg:
        issue("WARN", "annotations", f"{ann_no_seg} annotations have empty/missing 'segmentation'")
    if ann_neg_iscrowd:
        issue("WARN", "annotations",
              f"{ann_neg_iscrowd} annotations have invalid iscrowd value (not 0 or 1)")

    # ── Cross-checks ───────────────────────────────────────────
    imgs_with_ann = {ann.get("image_id") for ann in annotations}
    imgs_without_ann = img_id_set - imgs_with_ann
    if imgs_without_ann:
        issue("WARN", "cross-check",
              f"{len(imgs_without_ann)} images have no annotations")

    # Distribution stats (informational)
    ann_per_img = Counter(ann.get("image_id") for ann in annotations)
    if ann_per_img:
        counts = list(ann_per_img.values())
        max_ann = max(counts)
        avg_ann = sum(counts) / len(counts)
        if max_ann > 500:
            issue("WARN", "cross-check",
                  f"Some images have very many annotations (max={max_ann}, avg={avg_ann:.1f})")

    cat_usage = Counter(ann.get("category_id") for ann in annotations)
    unused_cats = [cid for cid in cat_id_set if cid not in cat_usage]
    if unused_cats:
        issue("WARN", "categories",
              f"{len(unused_cats)} categories have zero annotations", unused_cats)

    return issues


def main():
    data_dir = Path("./data")
    files = sorted(data_dir.glob("*.json"))
    if not files:
        print("No JSON files found in ./data")
        sys.exit(1)

    all_issues = {}
    for f in files:
        all_issues[f.name] = check_dataset(str(f))

    # ── Summary ────────────────────────────────────────────────
    print("\n" + "="*60)
    print("QUALITY REPORT SUMMARY")
    print("="*60)

    grand_errors = grand_warns = 0
    for fname, issues in all_issues.items():
        errors = [i for i in issues if i["severity"] == "ERROR"]
        warns  = [i for i in issues if i["severity"] == "WARN"]
        grand_errors += len(errors)
        grand_warns  += len(warns)
        print(f"\n📄 {fname}")
        if not issues:
            print("  ✅  No issues found.")
        else:
            for i in errors:
                print(f"  ❌  [ERROR/{i['category']}] {i['message']}")
                if i["detail"]:
                    print(f"        detail: {i['detail']}")
            for i in warns:
                print(f"  ⚠️   [WARN/{i['category']}]  {i['message']}")
                if i["detail"]:
                    print(f"        detail: {i['detail']}")

    print(f"\nTotal: {grand_errors} error(s), {grand_warns} warning(s) across {len(files)} file(s).")


if __name__ == "__main__":
    main()

